// Learn: Use default, static, and private interface methods.
interface Taxable {
  double rate();

  default double tax(double amount) {
    // default methods provide shared behavior to implementers.
    return clamp(amount) * rate();
  }

  static Taxable fixed(double value) {
    return () -> value;
  }

  private static double clamp(double value) {
    return Math.max(0.0, value);
  }
}
